+public partial class DocumentSummarizationService : IDocumentSummarizationService
+{
+    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
+    {
+        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
+        "in", "on", "at", "to", "for", "of", "with", "by", "it", "this",
+        "that", "from", "as", "be", "been", "being", "have", "has", "had",
+        "do", "does", "did", "will", "would", "could", "should", "may",
+        "might", "shall", "can", "not", "no", "so", "if", "then", "than",
+        "too", "very", "just", "about", "into", "through", "during", "before",
+        "after", "above", "below", "between", "out", "off", "over", "under",
+        "again", "further", "once", "here", "there", "when", "where", "why",
+        "how", "all", "each", "every", "both", "few", "more", "most", "other",
+        "some", "such", "only", "own", "same", "also", "its", "he", "she",
+        "they", "we", "you", "i", "me", "him", "her", "us", "them", "my",
+        "his", "their", "our", "your", "which", "what", "who", "whom"
+    };
+
+    public string Summarize(string documentText, int maxSentences)
+    {
+        var sentences = SplitIntoSentences(documentText);
+
+        if (sentences.Count <= maxSentences)
+            return string.Join(" ", sentences);
+
+        var wordFrequencies = ComputeWordFrequencies(sentences);
+        var scored = sentences
+            .Select((sentence, index) => (Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
+            .OrderByDescending(s => s.Score)
+            .Take(maxSentences)
+            .OrderBy(s => s.Index) // preserve original order
+            .Select(s => sentences[s.Index]);
+
+        return string.Join(" ", scored);
+    }
+
+    private static List<string> SplitIntoSentences(string text)
+    {
+        return SentenceBoundary().Matches(text)
+            .Select(m => m.Value.Trim())
+            .Where(s => s.Length > 0)
+            .ToList();
+    }
+
+    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
+    {
+        var freq = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);
+
+        foreach (var sentence in sentences)
+        {
+            foreach (var word in ExtractWords(sentence))
+            {
+                if (!StopWords.Contains(word))
+                    freq[word] = freq.GetValueOrDefault(word) + 1;
+            }
+        }
+
+        return freq;
+    }
+
+    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
+    {
+        var words = ExtractWords(sentence);
+        if (words.Count == 0)
+            return 0;
+
+        double total = words
+            .Where(w => !StopWords.Contains(w))
+            .Sum(w => wordFrequencies.GetValueOrDefault(w));
+
+        return total / words.Count;
+    }
+
+    private static List<string> ExtractWords(string text)
+    {
+        return WordPattern().Matches(text)
+            .Select(m => m.Value)
+            .ToList();
+    }
